    "title": "Đứa Con Gái Hoang Đàng - The Prodigal Daughter (Tái Bản 2023)",
    "author": "Jeffrey Archer",
    "publisher": "Bách Việt",
    "year": "2023",
    "sku": "9786044801216",
    "bookType": "Bìa Mềm",
    "language": "Tiếng Việt",
