    "handle": "tim-binh-yen-trong-gia-dinh",
    "sourceUrl": "https://www.vinabook.com/products/tim-binh-yen-trong-gia-dinh",
    "title": "Tìm Bình Yên Trong Gia Đình",
    "author": "Thích Nhất Hạnh",
    "publisher": "Thái Hà",
    "year": "2025",
